import React, { useState, useEffect } from 'react';

function PurchaseFunc() {
  const [purchases, setPurchases] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetchPurchases();
  }, []);

  const fetchPurchases = async () => {
    setIsLoading(true);
    setError(null);

    try {
      const response = await fetch('http://localhost:8081/PurchasesAPI');
      if (!response.ok) {
        throw new Error('Failed to fetch data');
      }
      const data = await response.json();
      setPurchases(data);
    } catch (error) {
      setError(error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSubmit = async (event) => {
    event.preventDefault();

    const formData = new FormData(event.target);
    const purchaseData = Object.fromEntries(formData.entries());

    try {
      const response = await fetch('http://localhost:8081/PurchasesAPI', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(purchaseData),
      });

      if (!response.ok) {
        throw new Error('Failed to add purchase');
      }

      // Fetch the updated list of purchases after successful addition
      fetchPurchases();
    } catch (error) {
      console.error(error);
    }
  };

  return (
    <div>
      <h1>My Purchases</h1>
      <form onSubmit={handleSubmit}>
        <label htmlFor="location">Location:</label>
        <input type="text" id="location" name="location" required />

        <label htmlFor="materialid">Material ID:</label>
        <input type="text" id="materialid" name="materialid" required />

        <label htmlFor="quantity">Quantity:</label>
        <input type="number" id="quantity" name="quantity" required />

        <button type="submit">Add Purchase</button>
      </form>

      {isLoading ? (
        <div>Loading...</div>
      ) : error ? (
        <div>Error: {error.message}</div>
      ) : (
        <table>
          <thead>
            <tr>
              <th>ID</th>
              <th>Location</th>
              <th>Material ID</th>
              <th>Quantity</th>
              <th>Date</th>
            </tr>
          </thead>
          <tbody>
            {purchases.map((purchase) => (
              <tr key={purchase.id}>
                <td>{purchase.id}</td>
                <td>{purchase.location}</td>
                <td>{purchase.materialid}</td>
                <td>{purchase.quantity}</td>
                <td>{purchase.date}</td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}

export default PurchaseFunc;
